// No partitions to archive
return [{
  json: {
    message: 'No partitions older than 7 years found',
    action: 'none',
    timestamp: new Date().toISOString()
  }
}];

// Prepare archive data as JSONL
const partitionInfo = $('Find Old Partitions').first().json;
const partitionName = partitionInfo.partition_name;
const rows = $input.all();

// Convert to JSONL format (one JSON object per line)
const jsonlContent = rows.map(r => r.json.json_row).join('\n');

// Create binary data for file writing
const binaryData = Buffer.from(jsonlContent, 'utf-8');

return [{
  json: {
    partition_name: partitionName,
    row_count: rows.length,
    filename: `${partitionName}.jsonl`,
    filepath: `/files/audit-archives/${partitionName}.jsonl`
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'application/x-ndjson',
      fileName: `${partitionName}.jsonl`
    }
  }
}];

// Archive verification failed
const archiveData = $('Prepare Archive Data').first().json;
const dbCount = $('Verify Row Count').first().json.archived_rows;

throw new Error(`Archive verification failed! ` +
  `File has ${archiveData.row_count} rows, DB has ${dbCount} rows. ` +
  `Partition NOT dropped. Manual intervention required.`);

// Final success summary
const archiveData = $('Prepare Archive Data').first().json;

return [{
  json: {
    status: 'success',
    message: 'Successfully archived and dropped partition',
    partition: archiveData.partition_name,
    rows_archived: archiveData.row_count,
    archive_file: archiveData.filepath,
    timestamp: new Date().toISOString()
  }
}];
